     1→/**
     2→ * InfiniteCanvas - Professional-grade pan/zoom canvas
     3→ *
     4→ * Features:
     5→ * - Pan with mouse drag (bounded to world limits)
     6→ * - Zoom with scroll wheel (centers on cursor position)
     7→ * - Initial view shows top-left of data (X=0, Y=0)
     8→ * - Sidebar sync via onViewportChange callback
     9→ *
    10→ * Coordinate System:
    11→ * - X: 0 = first day, positive = future (right)
    12→ * - Y: 0 = first train (TRAIN-001), negative = more trains (down)
    13→ *
    14→ * References:
    15→ * - D3.js zoom: https://d3js.org/d3-zoom
    16→ * - Three.js OrthographicCamera: https://threejs.org/docs/api/en/cameras/OrthographicCamera.html
    17→ * - pixi-viewport: https://github.com/pixijs-userland/pixi-viewport
    18→ */
    19→
    20→import { Canvas, useThree } from '@react-three/fiber';
    21→import { useState, useCallback, useMemo, useEffect, useRef } from 'react';
    22→import { MesoLayer } from './layers/MesoLayer';
    23→import { MacroLayer } from './layers/MacroLayer';
    24→import { MicroLayer } from './layers/MicroLayer';
    25→import { getRenderData } from '../data/generator';
    26→import type { LODLevel, WorldBounds } from '../data/types';
    27→import { DEFAULT_VIEW_CONFIG, calculateWorldBounds } from '../data/types';
    28→
    29→/**
    30→ * LOD Transition Configuration
    31→ *
    32→ * Defines blend zones around LOD thresholds for smooth transitions.
    33→ * During blend zones, both adjacent layers render with interpolated opacity.
    34→ */
    35→const LOD_THRESHOLDS = {
    36→  macroToMeso: 0.5,  // Below 0.5 = MACRO
    37→  mesoToMicro: 2.0,  // Above 2.0 = MICRO
    38→};
    39→
    40→// Size of blend zone around each threshold (±this value)
    41→const BLEND_ZONE_SIZE = 0.15;
    42→
    43→/**
    44→ * Calculate layer opacities for smooth LOD transitions
    45→ *
    46→ * Returns opacity values for each layer (0-1).
    47→ * During blend zones, adjacent layers overlap with interpolated opacity.
    48→ */
    49→function calculateLayerOpacities(zoom: number): {
    50→  macro: number;
    51→  meso: number;
    52→  micro: number;
    53→} {
    54→  const { macroToMeso, mesoToMicro } = LOD_THRESHOLDS;
    55→
    56→  // Define blend zone boundaries
    57→  const macroEnd = macroToMeso - BLEND_ZONE_SIZE; // 0.35
    58→  const mesoStart = macroToMeso + BLEND_ZONE_SIZE; // 0.65
    59→  const mesoEnd = mesoToMicro - BLEND_ZONE_SIZE; // 1.85
    60→  const microStart = mesoToMicro + BLEND_ZONE_SIZE; // 2.15
    61→
    62→  let macro = 0;
    63→  let meso = 0;
    64→  let micro = 0;
    65→
    66→  // Calculate MACRO opacity
    67→  if (zoom <= macroEnd) {
    68→    macro = 1;
    69→  } else if (zoom < mesoStart) {
    70→    // Blend zone MACRO → MESO
    71→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    72→    macro = 1 - t;
    73→  }
    74→
    75→  // Calculate MESO opacity
    76→  if (zoom < macroEnd) {
    77→    meso = 0;
    78→  } else if (zoom < mesoStart) {
    79→    // Blend zone MACRO → MESO
    80→    const t = (zoom - macroEnd) / (mesoStart - macroEnd);
    81→    meso = t;
    82→  } else if (zoom <= mesoEnd) {
    83→    meso = 1;
    84→  } else if (zoom < microStart) {
    85→    // Blend zone MESO → MICRO
    86→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    87→    meso = 1 - t;
    88→  }
    89→
    90→  // Calculate MICRO opacity
    91→  if (zoom <= mesoEnd) {
    92→    micro = 0;
    93→  } else if (zoom < microStart) {
    94→    // Blend zone MESO → MICRO
    95→    const t = (zoom - mesoEnd) / (microStart - mesoEnd);
    96→    micro = t;
    97→  } else {
    98→    micro = 1;
    99→  }
   100→
   101→  return { macro, meso, micro };
   102→}
   103→
   104→/**
   105→ * LODLayers - Orchestrates layer rendering with smooth transitions
   106→ *
   107→ * Renders multiple layers simultaneously during blend zones,
   108→ * with opacity interpolation for smooth visual transitions.
   109→ */
   110→function LODLayers({
   111→  tasks,
   112→  trainCount,
   113→  zoom,
   114→}: {
   115→  tasks: ReturnType<typeof getRenderData>['tasks'];
   116→  trainCount: number;
   117→  zoom: number;
   118→}) {
   119→  const opacities = useMemo(() => calculateLayerOpacities(zoom), [zoom]);
   120→
   121→  return (
   122→    <group>
   123→      {/* Render each layer if opacity > 0 */}
   124→      {opacities.macro > 0 && (
   125→        <MacroLayer
   126→          tasks={tasks}
   127→          trainCount={trainCount}
   128→          opacity={opacities.macro}
   129→        />
   130→      )}
   131→      {opacities.meso > 0 && (
   132→        <MesoLayer
   133→          tasks={tasks}
   134→          trainCount={trainCount}
   135→          opacity={opacities.meso}
   136→        />
   137→      )}
   138→      {opacities.micro > 0 && (
   139→        <MicroLayer
   140→          tasks={tasks}
   141→          trainCount={trainCount}
   142→          opacity={opacities.micro}
   143→        />
   144→      )}
   145→    </group>
   146→  );
   147→}
   148→
   149→interface InfiniteCanvasProps {
   150→  zoom: number;
   151→  lod: LODLevel;
   152→  onZoomChange: (zoom: number) => void;
   153→  /**
   154→   * Called when viewport position changes.
   155→   * @param topY - Y coordinate of the TOP of the viewport in world space
   156→   */
   157→  onViewportChange?: (topY: number) => void;
   158→}
   159→
   160→// Navigation limits
   161→const MIN_ZOOM = 0.1;
   162→const MAX_ZOOM = 5.0;
   163→
   164→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
   165→
   166→/**
   167→ * Camera controller component (inside R3F context)
   168→ * Handles initial positioning and syncs camera with external state
   169→ *
   170→ * IMPORTANT: Uses R3F's `size` from useThree() which is the actual canvas size,
   171→ * not the container div size (which can differ due to flexbox/layout).
   172→ */
   173→function CameraController({
   174→  cameraX,
   175→  cameraY,
   176→  zoom,
   177→  worldBounds,
   178→  isInitialized,
   179→  onInitialized,
   180→  onViewportChange,
   181→}: {
   182→  cameraX: number;
   183→  cameraY: number;
   184→  zoom: number;
   185→  worldBounds: WorldBounds;
   186→  isInitialized: boolean;
   187→  onInitialized: (pos: { x: number; y: number }, size: { width: number; height: number }) => void;
   188→  onViewportChange?: (topY: number) => void;
   189→}) {
   190→  const { camera, size } = useThree();
   191→
   192→  // Initialize camera position on first render using actual R3F size
   193→  useEffect(() => {
   194→    if (isInitialized || size.width === 0 || size.height === 0) return;
   195→
   196→    const halfViewX = size.width / 2 / zoom;
   197→    const halfViewY = size.height / 2 / zoom;
   198→
   199→    // Position camera to show top-left corner (X=0, Y=0)
   200→    const initialCameraX = halfViewX;
   201→    const initialCameraY = -halfViewY;
   202→
   203→    // Clamp to world bounds
   204→    const minCameraX = worldBounds.minX + halfViewX;
   205→    const maxCameraX = worldBounds.maxX - halfViewX;
   206→    const minCameraY = worldBounds.minY + halfViewY;
   207→    const maxCameraY = worldBounds.maxY - halfViewY;
   208→
   209→    const clampedX = Math.max(minCameraX, Math.min(maxCameraX, initialCameraX));
   210→    const clampedY = Math.max(minCameraY, Math.min(maxCameraY, initialCameraY));
   211→
   212→    // Update camera
   213→    camera.position.x = clampedX;
   214→    camera.position.y = clampedY;
   215→    (camera as any).zoom = zoom;
   216→    camera.updateProjectionMatrix();
   217→
   218→    // Notify parent of initial position and actual canvas size
   219→    onInitialized({ x: clampedX, y: clampedY }, { width: size.width, height: size.height });
   220→
   221→    // Notify viewport change
   222→    const topY = clampedY + halfViewY;
   223→    onViewportChange?.(topY);
   224→  }, [size, zoom, worldBounds, camera, isInitialized, onInitialized, onViewportChange]);
   225→
   226→  // Sync camera with external state changes (after initialization)
   227→  useEffect(() => {
   228→    if (!isInitialized) return;
   229→
   230→    camera.position.x = cameraX;
   231→    camera.position.y = cameraY;
   232→    (camera as any).zoom = zoom;
   233→    camera.updateProjectionMatrix();
   234→  }, [camera, cameraX, cameraY, zoom, isInitialized]);
   235→
   236→  return null;
   237→}
   238→
   239→export function InfiniteCanvas({
   240→  zoom,
   241→  lod,
   242→  onZoomChange,
   243→  onViewportChange,
   244→}: InfiniteCanvasProps) {
   245→  const containerRef = useRef<HTMLDivElement>(null);
   246→  const [isInitialized, setIsInitialized] = useState(false);
   247→  // Store actual canvas size from R3F (not container div)
   248→  const [canvasSize, setCanvasSize] = useState({ width: 800, height: 600 });
   249→
   250→  // Get render data (memoized)
   251→  const { trains, tasks } = useMemo(() => getRenderData(), []);
   252→
   253→  // Calculate world bounds (for pan clamping)
   254→  const worldBounds = useMemo<WorldBounds>(() => {
   255→    const totalDays = 365 * 10; // 10 years
   256→    return calculateWorldBounds(trains.length, totalDays);
   257→  }, [trains.length]);
   258→
   259→  // Camera position state
   260→  const [cameraPos, setCameraPos] = useState({ x: 0, y: 0 });
   261→
   262→  // Pan state
   263→  const [isPanning, setIsPanning] = useState(false);
   264→  const [panStart, setPanStart] = useState({ x: 0, y: 0 });
   265→  const [cameraPosAtPanStart, setCameraPosAtPanStart] = useState({ x: 0, y: 0 });
   266→
   267→  /**
   268→   * Called by CameraController when it initializes with actual R3F canvas size
   269→   */
   270→  const handleCameraInitialized = useCallback(
   271→    (pos: { x: number; y: number }, size: { width: number; height: number }) => {
   272→      setCameraPos(pos);
   273→      setCanvasSize(size);
   274→      setIsInitialized(true);
   275→    },
   276→    []
   277→  );
   278→
   279→  /**
   280→   * Calculate and notify the top Y position of the viewport
   281→   */
   282→  const notifyViewportChange = useCallback(
   283→    (camY: number, currentZoom: number) => {
   284→      const halfViewY = canvasSize.height / 2 / currentZoom;
   285→      const topY = camY + halfViewY;
   286→      onViewportChange?.(topY);
   287→    },
   288→    [canvasSize.height, onViewportChange]
   289→  );
   290→
   291→  /**
   292→   * Clamp camera position to world bounds
   293→   */
   294→  const clampCameraToWorld = useCallback(
   295→    (x: number, y: number, currentZoom: number): { x: number; y: number } => {
   296→      const halfViewX = canvasSize.width / 2 / currentZoom;
   297→      const halfViewY = canvasSize.height / 2 / currentZoom;
   298→
   299→      const minCameraX = worldBounds.minX + halfViewX;
   300→      const maxCameraX = worldBounds.maxX - halfViewX;
   301→      const minCameraY = worldBounds.minY + halfViewY;
   302→      const maxCameraY = worldBounds.maxY - halfViewY;
   303→
   304→      const clampedX =
   305→        maxCameraX < minCameraX
   306→          ? (worldBounds.minX + worldBounds.maxX) / 2
   307→          : Math.max(minCameraX, Math.min(maxCameraX, x));
   308→
   309→      const clampedY =
   310→        maxCameraY < minCameraY
   311→          ? (worldBounds.minY + worldBounds.maxY) / 2
   312→          : Math.max(minCameraY, Math.min(maxCameraY, y));
   313→
   314→      return { x: clampedX, y: clampedY };
   315→    },
   316→    [canvasSize, worldBounds]
   317→  );
   318→
   319→  /**
   320→   * Handle wheel zoom - zoom toward cursor position
   321→   * Based on the pattern from D3.js zoom behavior
   322→   */
   323→  const handleWheel = useCallback(
   324→    (e: WheelEvent) => {
   325→      e.preventDefault();
   326→      if (!isInitialized) return;
   327→
   328→      const zoomFactor = e.deltaY > 0 ? 0.9 : 1.1;
   329→      const newZoom = Math.max(MIN_ZOOM, Math.min(MAX_ZOOM, zoom * zoomFactor));
   330→
   331→      if (newZoom === zoom) return;
   332→
   333→      const rect = containerRef.current?.getBoundingClientRect();
   334→      if (!rect) return;
   335→
   336→      // Cursor position relative to canvas center
   337→      const cursorX = e.clientX - rect.left - rect.width / 2;
   338→      const cursorY = e.clientY - rect.top - rect.height / 2;
   339→
   340→      // Convert cursor to world coordinates (before zoom)
   341→      const worldX = cursorX / zoom + cameraPos.x;
   342→      const worldY = -cursorY / zoom + cameraPos.y;
   343→
   344→      // Calculate new camera position to keep cursor point fixed
   345→      const newCameraX = worldX - cursorX / newZoom;
   346→      const newCameraY = worldY + cursorY / newZoom;
   347→
   348→      const clamped = clampCameraToWorld(newCameraX, newCameraY, newZoom);
   349→
   350→      setCameraPos(clamped);
   351→      onZoomChange(newZoom);
   352→      notifyViewportChange(clamped.y, newZoom);
   353→    },
   354→    [zoom, cameraPos, clampCameraToWorld, onZoomChange, notifyViewportChange, isInitialized]
   355→  );
   356→
   357→  // Register wheel event with { passive: false } to allow preventDefault
   358→  useEffect(() => {
   359→    const container = containerRef.current;
   360→    if (!container) return;
   361→
   362→    container.addEventListener('wheel', handleWheel, { passive: false });
   363→    return () => container.removeEventListener('wheel', handleWheel);
   364→  }, [handleWheel]);
   365→
   366→  /**
   367→   * Handle pan start
   368→   */
   369→  const handlePointerDown = useCallback(
   370→    (e: React.PointerEvent) => {
   371→      if (!isInitialized) return;
   372→      setIsPanning(true);
   373→      setPanStart({ x: e.clientX, y: e.clientY });
   374→      setCameraPosAtPanStart(cameraPos);
   375→      (e.target as HTMLElement).setPointerCapture(e.pointerId);
   376→    },
   377→    [cameraPos, isInitialized]
   378→  );
   379→
   380→  /**
   381→   * Handle pan move
   382→   */
   383→  const handlePointerMove = useCallback(
   384→    (e: React.PointerEvent) => {
   385→      if (!isPanning) return;
   386→
   387→      const dx = (e.clientX - panStart.x) / zoom;
   388→      const dy = (e.clientY - panStart.y) / zoom;
   389→
   390→      const newX = cameraPosAtPanStart.x - dx;
   391→      const newY = cameraPosAtPanStart.y + dy;
   392→
   393→      const clamped = clampCameraToWorld(newX, newY, zoom);
   394→
   395→      setCameraPos(clamped);
   396→      notifyViewportChange(clamped.y, zoom);
   397→    },
   398→    [isPanning, panStart, cameraPosAtPanStart, zoom, clampCameraToWorld, notifyViewportChange]
   399→  );
   400→
   401→  /**
   402→   * Handle pan end
   403→   */
   404→  const handlePointerUp = useCallback((e: React.PointerEvent) => {
   405→    setIsPanning(false);
   406→    (e.target as HTMLElement).releasePointerCapture(e.pointerId);
   407→  }, []);
   408→
   409→  return (
   410→    <div
   411→      ref={containerRef}
   412→      style={{
   413→        width: '100%',
   414→        height: '100%',
   415→        cursor: isPanning ? 'grabbing' : 'grab',
   416→        touchAction: 'none',
   417→      }}
   418→      onPointerDown={handlePointerDown}
   419→      onPointerMove={handlePointerMove}
   420→      onPointerUp={handlePointerUp}
   421→      onPointerLeave={handlePointerUp}
   422→    >
   423→      <Canvas
   424→        gl={{ antialias: true, alpha: false }}
   425→        style={{ background: '#f4f4f5' }}
   426→        orthographic
   427→        camera={{
   428→          position: [cameraPos.x, cameraPos.y, 100],
   429→          zoom: zoom,
   430→          near: 0.1,
   431→          far: 1000,
   432→        }}
   433→      >
   434→        <CameraController
   435→          cameraX={cameraPos.x}
   436→          cameraY={cameraPos.y}
   437→          zoom={zoom}
   438→          worldBounds={worldBounds}
   439→          isInitialized={isInitialized}
   440→          onInitialized={handleCameraInitialized}
   441→          onViewportChange={onViewportChange}
   442→        />
   443→
   444→        <color attach="background" args={['#f4f4f5']} />
   445→
   446→        {/* LOD-based layer rendering with smooth transitions */}
   447→        <LODLayers
   448→          tasks={tasks}
   449→          trainCount={trains.length}
   450→          zoom={zoom}
   451→        />
   452→      </Canvas>
   453→    </div>
   454→  );
   455→}
   456→

