/**
 * MesoLayer - DNA-like task block visualization
 *
 * Renders task blocks using InstancedMesh for optimal performance.
 * Visible at zoom levels 0.5x - 2.0x (MESO LOD level).
 *
 * Features:
 * - InstancedMesh for all task blocks (single draw call)
 * - Color coding: blue (maintenance), orange (overhaul), gray (inspection)
 * - Conflict indicators: red border effect on hasConflict tasks
 * - Alternating row backgrounds for readability
 */

import { useMemo, useRef, useEffect } from 'react';
import { InstancedMesh, Object3D, Color, Matrix4 } from 'three';
import type { TaskRender } from '../../data/types';
import { DEFAULT_VIEW_CONFIG } from '../../data/types';

interface MesoLayerProps {
  tasks: TaskRender[];
  trainCount: number;
  /** Opacity for LOD transitions (0-1). Default: 1 */
  opacity?: number;
}

// Color palette matching POC reference
const COLORS: Record<string, string> = {
  blue: '#3b82f6',    // maintenance
  orange: '#f59e0b',  // overhaul
  gray: '#9ca3af',    // inspection
};

const CONFLICT_COLOR = '#ef4444'; // red for conflicts

// Row background colors (alternating)
const ROW_BG_EVEN = '#ffffff';
const ROW_BG_ODD = '#f8fafc';

const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;

// Task block height (with padding)
const TASK_HEIGHT = pxPerTrain - 4; // 20px height with 2px padding top/bottom
const TASK_PADDING_Y = 2;

/**
 * Renders alternating row backgrounds for train rows
 */
function RowBackgrounds({
  trainCount,
  totalDays,
  opacity = 1,
}: {
  trainCount: number;
  totalDays: number;
  opacity?: number;
}) {
  const totalWidth = totalDays * pxPerDay;

  return (
    <group>
      {Array.from({ length: trainCount }, (_, i) => (
        <mesh
          key={`row-${i}`}
          position={[
            totalWidth / 2, // Center the row
            -i * pxPerTrain - pxPerTrain / 2, // Y position (negative = down)
            -0.1, // Behind tasks
          ]}
        >
          <planeGeometry args={[totalWidth, pxPerTrain]} />
          <meshBasicMaterial
            color={i % 2 === 0 ? ROW_BG_EVEN : ROW_BG_ODD}
            transparent
            opacity={0.5 * opacity}
          />
        </mesh>
      ))}
    </group>
  );
}

/**
 * Main task blocks using InstancedMesh
 */
function TaskBlocks({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);
  const tempMatrix = useMemo(() => new Matrix4(), []);

  // Update instance matrices and colors when tasks change
  useEffect(() => {
    if (!meshRef.current) return;

    const mesh = meshRef.current;

    tasks.forEach((task, i) => {
      // Calculate position and size
      const width = task.duration * pxPerDay;
      const height = TASK_HEIGHT;
      const x = task.startDay * pxPerDay + width / 2; // Center of task
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2; // Negative Y (down)
      const z = task.hasConflict ? 0.1 : 0; // Conflicts slightly forward

      // Set transform
      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);

      // Set color
      const color = task.hasConflict
        ? new Color(CONFLICT_COLOR)
        : new Color(COLORS[task.color]);
      mesh.setColorAt(i, color);
    });

    // Mark buffers for update
    mesh.instanceMatrix.needsUpdate = true;
    if (mesh.instanceColor) {
      mesh.instanceColor.needsUpdate = true;
    }
  }, [tasks, tempObject]);

  if (tasks.length === 0) {
    return null;
  }

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, tasks.length]}
    >
      {/* Unit plane centered at origin - will be scaled by instance matrix */}
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial toneMapped={false} transparent={opacity < 1} opacity={opacity} />
    </instancedMesh>
  );
}

/**
 * Conflict glow effect layer
 * Renders a subtle glow behind conflict tasks
 */
function ConflictGlows({ tasks, opacity = 1 }: { tasks: TaskRender[]; opacity?: number }) {
  const conflictTasks = useMemo(
    () => tasks.filter((t) => t.hasConflict),
    [tasks]
  );

  const meshRef = useRef<InstancedMesh>(null);
  const tempObject = useMemo(() => new Object3D(), []);

  useEffect(() => {
    if (!meshRef.current || conflictTasks.length === 0) return;

    const mesh = meshRef.current;

    conflictTasks.forEach((task, i) => {
      const width = task.duration * pxPerDay + 6; // Slightly larger for glow
      const height = TASK_HEIGHT + 6;
      const x = task.startDay * pxPerDay + (task.duration * pxPerDay) / 2;
      const y = -task.trainIndex * pxPerTrain - pxPerTrain / 2;
      const z = -0.05; // Behind the task block

      tempObject.position.set(x, y, z);
      tempObject.scale.set(width, height, 1);
      tempObject.updateMatrix();
      mesh.setMatrixAt(i, tempObject.matrix);
    });

    mesh.instanceMatrix.needsUpdate = true;
  }, [conflictTasks, tempObject]);

  if (conflictTasks.length === 0) {
    return null;
  }

  return (
    <instancedMesh
      ref={meshRef}
      args={[undefined, undefined, conflictTasks.length]}
    >
      <planeGeometry args={[1, 1]} />
      <meshBasicMaterial
        color={CONFLICT_COLOR}
        transparent
        opacity={0.3 * opacity}
      />
    </instancedMesh>
  );
}

/**
 * MesoLayer Component
 *
 * Renders the DNA-like task block visualization for the MESO LOD level.
 */
export function MesoLayer({ tasks, trainCount, opacity = 1 }: MesoLayerProps) {
  // Calculate total days for row backgrounds
  const totalDays = useMemo(() => {
    if (tasks.length === 0) return 365 * 10; // Default: 10 years
    const maxDay = Math.max(...tasks.map((t) => t.startDay + t.duration));
    return Math.max(maxDay + 30, 365 * 10); // Add padding
  }, [tasks]);

  return (
    <group>
      {/* Row backgrounds (behind everything) */}
      <RowBackgrounds trainCount={trainCount} totalDays={totalDays} opacity={opacity} />

      {/* Conflict glow effects (behind task blocks) */}
      <ConflictGlows tasks={tasks} opacity={opacity} />

      {/* Main task blocks */}
      <TaskBlocks tasks={tasks} opacity={opacity} />
    </group>
  );
}

