     1→/**
     2→ * MacroLayer - Strategic heatmap visualization
     3→ *
     4→ * Renders a heatmap showing task density across trains and time.
     5→ * Visible at zoom levels < 0.5x (MACRO LOD level).
     6→ *
     7→ * Features:
     8→ * - Aggregates tasks by month/train into cells
     9→ * - Color gradient: yellow (low) → orange (medium) → red (high density)
    10→ * - InstancedMesh for optimal performance
    11→ * - Shows 10-20 year strategic overview
    12→ */
    13→
    14→import { useMemo, useRef, useEffect } from 'react';
    15→import { InstancedMesh, Object3D, Color } from 'three';
    16→import type { TaskRender } from '../../data/types';
    17→import { DEFAULT_VIEW_CONFIG } from '../../data/types';
    18→
    19→interface MacroLayerProps {
    20→  tasks: TaskRender[];
    21→  trainCount: number;
    22→  totalYears?: number;
    23→  /** Opacity for LOD transitions (0-1). Default: 1 */
    24→  opacity?: number;
    25→}
    26→
    27→const { pxPerDay, pxPerTrain } = DEFAULT_VIEW_CONFIG;
    28→
    29→// Heatmap cell size
    30→const DAYS_PER_CELL = 30; // ~1 month per cell
    31→const CELL_WIDTH = DAYS_PER_CELL * pxPerDay; // 300px
    32→const CELL_HEIGHT = pxPerTrain; // 24px per train row
    33→const CELL_GAP = 1; // Small gap between cells
    34→
    35→// Heatmap color gradient: yellow → orange → red
    36→const HEATMAP_COLORS = {
    37→  low: '#fef3c7',     // yellow-100 (very light)
    38→  medium: '#fbbf24',  // amber-400
    39→  high: '#f97316',    // orange-500
    40→  critical: '#dc2626', // red-600
    41→};
    42→
    43→/**
    44→ * Interpolate between colors based on density (0-1)
    45→ */
    46→function getHeatmapColor(density: number): Color {
    47→  // No tasks = light background
    48→  if (density === 0) {
    49→    return new Color('#f8fafc'); // slate-50
    50→  }
    51→
    52→  // Normalize density (0-1 range, with max around 10 tasks)
    53→  const normalizedDensity = Math.min(density / 8, 1);
    54→
    55→  // Four-stop gradient: light yellow → yellow → orange → red
    56→  if (normalizedDensity < 0.25) {
    57→    // Light yellow to yellow
    58→    const t = normalizedDensity / 0.25;
    59→    return new Color(HEATMAP_COLORS.low).lerp(new Color(HEATMAP_COLORS.medium), t);
    60→  } else if (normalizedDensity < 0.5) {
    61→    // Yellow to orange
    62→    const t = (normalizedDensity - 0.25) / 0.25;
    63→    return new Color(HEATMAP_COLORS.medium).lerp(new Color(HEATMAP_COLORS.high), t);
    64→  } else {
    65→    // Orange to red
    66→    const t = (normalizedDensity - 0.5) / 0.5;
    67→    return new Color(HEATMAP_COLORS.high).lerp(new Color(HEATMAP_COLORS.critical), t);
    68→  }
    69→}
    70→
    71→/**
    72→ * Calculate task density per cell
    73→ * Returns a 2D array: [trainIndex][monthIndex] = task count
    74→ */
    75→function calculateDensityGrid(
    76→  tasks: TaskRender[],
    77→  trainCount: number,
    78→  totalMonths: number
    79→): number[][] {
    80→  // Initialize grid with zeros
    81→  const grid: number[][] = Array.from({ length: trainCount }, () =>
    82→    Array(totalMonths).fill(0)
    83→  );
    84→
    85→  // Count tasks in each cell
    86→  for (const task of tasks) {
    87→    // Calculate which month(s) this task spans
    88→    const startMonth = Math.floor(task.startDay / DAYS_PER_CELL);
    89→    const endMonth = Math.floor((task.startDay + task.duration) / DAYS_PER_CELL);
    90→
    91→    // Increment count for all months the task spans
    92→    for (let month = startMonth; month <= endMonth && month < totalMonths; month++) {
    93→      if (month >= 0 && task.trainIndex >= 0 && task.trainIndex < trainCount) {
    94→        grid[task.trainIndex][month]++;
    95→      }
    96→    }
    97→  }
    98→
    99→  return grid;
   100→}
   101→
   102→/**
   103→ * MacroLayer Component
   104→ *
   105→ * Renders the strategic heatmap visualization for the MACRO LOD level.
   106→ */
   107→export function MacroLayer({ tasks, trainCount, totalYears = 10, opacity = 1 }: MacroLayerProps) {
   108→  const meshRef = useRef<InstancedMesh>(null);
   109→  const tempObject = useMemo(() => new Object3D(), []);
   110→
   111→  // Calculate grid dimensions
   112→  const totalMonths = totalYears * 12;
   113→  const totalCells = trainCount * totalMonths;
   114→
