   310→  manHours?: number;
   311→  estimatedCost?: number;
   312→  dependencies?: string[];
   313→  status?: 'scheduled' | 'in-progress' | 'completed';
   314→}
   315→
   316→// Conflict as separate entity (future)
   317→export interface Conflict {
   318→  id: string;
   319→  taskIds: [string, string];
   320→  type: 'overlap' | 'resource' | 'dependency';
   321→  severity: 'low' | 'medium' | 'high';
   322→  description?: string;
   323→}
